if (tokens && tokens.length > 0) {
  for (const token of tokens) {
    const balance = parseFloat(token.balance_formatted || '0')

    if (balance === 0 || isNaN(balance)) {
      continue
    }

    // Determine chain ID based on token (Moralis doesn't return chain per token in this response)
    // We'll need to fetch per chain, so let's update the hook
    // For now, group all tokens by checking which chain they belong to
    let chainId = 1 // Default to Ethereum

    // Since Moralis returns all tokens together, we need to track which chain each came from
    // This is a limitation - let me update the hook to return chain info

    const logoUrl = token.logo || token.thumbnail || undefined

    if (!chainData.has(chainId)) {
      chainData.set(chainId, {
        chainId,
        chainName: supportedChains.find(c => c.id === chainId)?.name || 'Unknown',
        valueUsd: 0,
        tokens: []
      })
    }

    const chain = chainData.get(chainId)!

    const priceUsd = token.usd_price || 0
    const valueUsd = token.usd_value || 0

    chain.tokens.push({
      address: token.token_address,
      symbol: token.symbol,
      name: token.name,
      balance: token.balance,
      balanceFormatted: token.balance_formatted || balance.toFixed(6),
      valueUsd,
      priceUsd,
      logo: logoUrl,
    })

    chain.valueUsd += valueUsd
    totalValue += valueUsd
  }
}

